
Print('update BalanceAware in deal')
go
Update cre.deal set BalanceAware = 0
Update cre.deal set BalanceAware = 1 where credealid in ('18-2204','16-1405')
go


Print('update TransactionTypes')
go
Update [CRE].[TransactionTypes] set [AccountName] = TransactionName
update  [CRE].[TransactionTypes] set AccountName ='periodint' where TransactionName ='InterestPaid'
update  [CRE].[TransactionTypes] set AccountName ='periodpikint' where TransactionName ='PIKInterest'
update  [CRE].[TransactionTypes] set AccountName ='periodpikintpaid' where TransactionName ='PIKInterestPaid'
update  [CRE].[TransactionTypes] set AccountName ='pikprinpaid' where TransactionName ='PIKPrincipalPaid'
go



Print('Insert JsonTemplate')
go
Truncate table [CRE].[JsonTemplate]
GO
SET IDENTITY_INSERT [CRE].[JsonTemplate] ON 
INSERT [CRE].[JsonTemplate] ([Id], [Key], [Value], [Type], [FileName]) VALUES (1, N'rules', N'[{"description":"Attach a rule which should be executed when an account is updated","type":"attach_rules_to_accounts","config":{"paydown":[{"description":"Calculate Exit Fee","type":"foreach","condition":"(@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in [''Exit Fee'', ''Exit Fee_IncAmor'']]","rules":[{"description":"Fee","type":"accumulate","condition":"pd.Timestamp(@fee.startdt) <= @date <= pd.Timestamp(@fee.enddt)","context":[{"name":"fee_type","expression":"@fee.type"},{"name":"fee_name","expression":"@fee.feename"}],"config":{"filter":"(@df.Date == @date)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["[-@amount]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl"]}}}]}}],"fee_stripped":[{"description":"Calculate Fee Stripping","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee_stripping'']))","config":{"foreach_variable_name":"strip","expression":"@note[@effective_date].fee_stripping","rules":[{"description":"Add StripReceivable transactions","type":"add_cashflow","config":{"Date":"@date","Note":"@strip.to","type":"@fee_type","expression":"@amount * @strip.pct","addl_columns":{"Fee Name":"@fee_name","Effective Date":"@effective_date","Parent Note":"@root_note_id"}}}]}}]}},{"description":"For each effective date, execute the following rules","type":"foreach","config":{"foreach_variable_name":"effective_date","expression":"@effective_dates","rules":[{"description":"Delete data for dates greater than effective date","type":"reset","config":{"df":"@df.Date >= pd.Timestamp(@effective_date)","cf":"(@cf.Date >= pd.Timestamp(@effective_date)) & (@cf.Note == @root_note_id)"}},{"description":"Setup note context for effective date","context":[{"name":"note","expression":"@notes[@root_note_id]"},{"name":"is_legal_note","expression":"@note.type == ''legal''"},{"name":"is_closed_note","expression":"@if_exists(@note, [@effective_date], [])"},{"name":"is_closing_effective_date","expression":"@is_closed_note & (pd.Timestamp(@note[@effective_date].clsdt) == pd.Timestamp(@effective_date))"}]},{"description":"Add Initial Funding transaction","type":"add_cashflow","condition":"@is_closing_effective_date","config":{"Date":"pd.Timestamp(@note[@effective_date].clsdt)","Note":"@note.id","type":"InitialFunding","expression":"@note[@effective_date].initbal"}},{"description":"Read values from note setup","type":"read_dict","condition":"@is_closed_note","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","expression":"@note[@effective_date]"}},{"description":"Read records from tables in note setup - Rate","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''rate'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"rate","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].rate","''startdt''"]}}},{"description":"Read records from tables in note setup - Spread","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''spread'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"spread","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].spread","''startdt''"]}}},{"description":"Read records from tables in note setup - Index Floor","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''index_floor'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"index_floor","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].index_floor","''startdt''"]}}},{"description":"Read records from tables in note setup - Index Cap","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''index_cap'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"index_cap","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].index_cap","''startdt''"]}}},{"description":"Read records from tables in note setup - Coupon Floor","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''coupon_floor'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"coupon_floor","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].coupon_floor","''startdt''"]}}},{"description":"Read records from tables in note setup - Amort Rate","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''amort_rate'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"amort_rate","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].amort_rate","''startdt''"]}}},{"description":"Read records from tables in note setup - PIK Rate","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''pikrate'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"pikrate","function":{"name":"get_pikrates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].pikrate","''startdt''","''enddt''"]}}},{"description":"Allocate Fundings to the notes","type":"pay","ignoreerror":"False","conditio