n":"Identify io term end date","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''initpmtdt'',''ioterm'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["io_term_end_date"],"expression":"@df.initpmtdt[0] + pd.DateOffset(months=@df.ioterm[0] - 1)"}},{"description":"Read actuals - Payment date","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''actuals''])","config":{"foreach_variable_name":"actual","expression":"[x for x in @note[@effective_date].actuals if x.account in [''periodpikintpaid'', ''periodint'']]","rules":[{"description":"Assign actuals to df","type":"accumulate","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.term > 0) & (@df.pmtdt == pd.Timestamp(@actual.dt)) & (@df.Date == @df.periodend)","columns":"[''act_'' + @actual.account]","expression":"@actual.val"}}]}},{"description":"Read actuals - Transaction date","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''actuals''])","config":{"foreach_variable_name":"actual","expression":"[x for x in @note[@effective_date].actuals if x.account in [''pikprinpaid'']]","rules":[{"description":"Assign actuals to df","type":"accumulate","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.Date == pd.Timestamp(@actual.dt))","columns":"[''act_'' + @actual.account]","expression":"@actual.val"}}]}},{"description":"Calculate Schedule Principal - Debt Service Override","type":"assignment","condition":"@note[@effective_date].monamovrd > 0","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.term > 0) & (@df.Date == @df.periodend) & (@df.Date < @df.initmatdt)","columns":["schprin"],"expression":"@df.monamovrd"}},{"description":"Calculate Schedule Principal - Amort Schedule","type":"foreach","condition":"(@note[@effective_date].monamovrd == 0) & (@if_exists(@note, [@effective_date], [''amsch'']))","config":{"foreach_variable_name":"amort","expression":"@note[@effective_date].amsch","rules":[{"description":"Assign amort to df","type":"accumulate","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.term > 0) & (@df.pmtdt == pd.Timestamp(@amort.dt)) & (@df.Date == @df.periodend)","columns":["schprin"],"expression":"@amort.val"}}]}},{"description":"Set Discount/Premium - Initialize","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''discount'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["discount"],"value":0}},{"description":"Set Discount/Premium","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''discount'']))","config":{"filter":"(@df.Date == @df.clsdt)","columns":["discount"],"expression":"@note[@effective_date].discount * -1"}},{"description":"Set Capitalized Closing Costs - Initialize","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''capcosts'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["capcosts"],"value":0}},{"description":"Set Capitalized Closing Costs","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''capcosts'']))","config":{"filter":"(@df.Date == @df.clsdt)","columns":["capcosts"],"expression":"@note[@effective_date].capcosts"}},{"description":"Identify Index Rate","type":"assignment","condition":"@is_legal_note & @is_closed_note","config":{"columns":["indexrate"],"function":{"name":"get_index_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@index","@df.roundmethod[0]","@df.precision[0]","@df.clsdt[0]","@df.initresetdt[0]","@df[@df.term >= 1].periodstart.unique()","@df[@df.term >= 1].indexrefdt.unique()","@df.initindex[0]","@df.index_floor_val","@df.index_cap_val"]}}},{"description":"Identify All In Coupon Rate","type":"assignment","condition":"@is_legal_note & @is_closed_note","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["allincouponrate","allinadjfactor"],"function":{"name":"get_all_in_coupon_rate","module":"rates","package":"m61_finance.cre","parameters":["@df.coupon_floor_val","@df.spread_val","@df.spread_adj_factor","@df.rate_val","@df.rate_adj_factor","@df.indexrate",["allincouponrate","allinadjfactor"]]}}},{"description":"Calculate All In PIK Rate","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''pikrate'']))","context":[{"name":"is_floatingpik","expression":"@note[@effective_date][''pikrate''][0].rate == 0"}],"config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["allinpikrate"],"function":{"name":"get_allin_pikrate","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@df.pikrate_rate","@df.pikrate_spread","@df.indexrate","@df.pikrate_index_floor","@is_floatingpik"]}}},{"description":"Identify remaining term","type":"assignment","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (~@df.amterm.isna())","columns":["rem_term"],"expression":"@df.amterm - @df.term"}},{"description":"For each day, execute the following rules","type":"foreach","config":{"foreach_variable_name":"period","expression":"@df.Date[pd.Timestamp(@effective_date):].unique()","rules":[{"description":"Evaluate Period Filter","context":[{"name":"is_period","expression":"(@df.Date == @period) & (@df.clsdt.notna())"}]},{"description":"Calculate Scheduled Principal","type":"assignment","condition":"(@note[@effective_date].monamovrd == 0) & (not @if_exists(@note, [@effective_date], [''amsch'']))","config":{"filter":"@is_period & (@df.Date == @df.periodend) & (@df.Date > @df.io_term_end_date) & (@df.rem_term > 0) & (@df.amort_rate_val > 0)","columns":["schprin"],"function":{"name":"scheduled_principal","module":"balance","package":"m61_finance.cre","parameters":["@df.initbal","@df.amort_rate_val","@df.rem_term"]}}},{"description":"Calculate Daily PIK Interest","type":"assignment","config":{"filter":"@is_period","columns":["dailypikint"],"function":{"name":"daily_accrued_interest","module":"coupon","package":"m61_finance.cre","parameters":["@df.initbal","@df.allinpikrate","@df.pikrate_adj_factor"]}}},{"description":"Calculate PIK Interest Per Period","type":"assignment","context":[{"name":"cum_dailypikint","expression":"@df.loc[@df.term == @df.loc[@is_period, ''term''][0]].dailypikint.sum()"}],"config":{"filter":"@is_period & (@df.term > 0)","columns":["cum_dailypikint"],"expression":"@cum_dailypikint"}},{"description":"Calculate Accrual Period PIK Interest","type":"assignment","config":{"filter":"@is_period & (@df.term > 0) & (@df.Date == @df.periodend) & (@df.cum_dailypikint > @df.act_periodpikintpaid)","columns":["periodpikint"],"expression":"@df.cum_dailypikint - @df.act_periodpikintpaid"}},{"description":"Calculate Balloon Payment","type":"assignment","config":{"filter":"@is_period & (@df.Date == @df.initmatdt)","columns":["balloon"],"function":{"name":"balloon_payment","module":"balance","package":"m61_finance.cre","parameters":["@df.initbal","@df[@is_period].funding + @df[@is_period].paydown","@df.schprin"]}}},{"description":"Calculate ending balance","type":"assignment","context":[{"name":"ending_balance","function":{"name":"ending_balance","module":"balance","package":"m61_finance.cre","parameters":["@df[@is_period].initbal","@df[@is_period].funding + @df[@is_period].paydown","@df[@is_period].schprin","@df[@is_period].periodpikint","@df[@is_period].balloon"]}}],"config":{"filter":"@is_period","columns":["endbal"],"expression":"@ending_balance"}},{"description":"Calculate beginning balance","type":"assignment","config":{"filter":"(@df.Date == (pd.Timestamp(@period) + pd.DateOffset())) & (@df.clsdt.notna())","columns":["initbal"],"expression":"@ending_balance.to_numpy()"}}]}},{"description":"Calculate Daily Interest","type":"assignment","config":{"colum