e == pd.Timestamp(@fee.startdt)) & (pd.Timestamp(@effective_date) <= pd.Timestamp(@fee.startdt))) if @config.fee.config[@fee.type].coverage == ''Date Specific'' else ((@df.Date >= pd.Timestamp(@fee.startdt)) & (@df.Date <= pd.Timestamp(@fee.enddt)) & (@df.Date >= pd.Timestamp(@effective_date)))"}],"config":{"filter":"(@fee_filter) & (@df[@account] != 0)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["@df[@account]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl"]}}}]}}]}},{"description":"Calculate Gross Deferred Fee for the Effective Date","type":"assignment","config":{"filter":"@df.Date >= pd.Timestamp(@effective_date)","columns":["gross_def_fees"],"expression":"@df.fee_incl_lv_yield.sum()"}},{"description":"Calculate Clean Cost","type":"assignment","config":{"filter":"@df.Date >= pd.Timestamp(@effective_date)","columns":["clean_cost"],"expression":"@df.endbal - @df.gross_def_fees + @df.discount  + @df.capcosts"}},{"description":"Calculate Clean Cost - Convert to Float","type":"assignment","config":{"columns":["float_clean_cost"],"expression":"@df.clean_cost.astype(''float64'')"}},{"description":"For each note, execute the basis rules","type":"foreach","condition":"@calc_basis","config":{"foreach_variable_name":"note","expression":"@notes.values()","rules":[{"description":"Calculate Level Yield - Deferred Fee Yield","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","context":[{"name":"prev_gaapbasis","expression":"-@df.at[(pd.Timestamp(@effective_date), @note.id), ''initbal''] if @is_closing_effective_date else -@df.at[(pd.Timestamp(@effective_date) - pd.DateOffset(), @note.id), ''gaapbasis'']"}],"config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["levyld"],"function":{"name":"calculate_level_yield","module":"basis","package":"m61_finance.cre","parameter