ote.id), ''bas_disc'']"}],"config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["yld_disc"],"function":{"name":"calculate_level_yield","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal-@df.endbal+@df.discount","pd.Timestamp(@effective_date) if @is_closing_effective_date else (pd.Timestamp(@effective_date) - pd.DateOffset())","@prev_gaapbasis"]}}},{"description":"Calculate Gaap Basis - Discout/Premium Basis","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["bas_disc"],"function":{"name":"calculate_gaapbasis","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal-@df.endbal","@df.discount","@df.yld_disc[0]"]}}},{"description":"Calculate Fee Amort","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["am_disc"],"function":{"name":"calculate_feeamort","module":"basis","package":"m61_finance.cre","parameters":["@df.initbal-@df.endbal","@df.discount","@df.bas_disc"]}}},{"description":"Calculate Cumulative Amort(Discount) - Convert to Float","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["float_am_disc"],"expression":"@df.am_disc.astype(''float64'')"}},{"description":"Calculate Cumulative Amort (Discout)","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["cum_am_disc"],"expression":"@df.float_am_disc.cum