n":"@if_exists(@note, [@effective_date], [''funding''])","config":{"source":"[x for x in @note[@effective_date].funding if x.fundpydn > 0 and pd.Timestamp(x.dt) >= pd.Timestamp(@effective_date)]","amount_col":"fundpydn","date_col":"dt","account":"funding","rules":[{"description":"Pay everything to the note","config":{"note":"@note.id","weight":1}}]}},{"description":"Allocate Paydowns to the notes","type":"pay","ignoreerror":"False","condition":"@if_exists(@note, [@effective_date], [''funding''])","config":{"source":"[x for x in @note[@effective_date].funding if x.fundpydn < 0 and pd.Timestamp(x.dt) >= pd.Timestamp(@effective_date)]","amount_col":"fundpydn","date_col":"dt","account":"paydown","rules":[{"description":"Pay everything to the note","config":{"note":"@note.id","weight":1}}]}},{"description":"Assign strip receivables","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''fee_strip_received''])","config":{"foreach_variable_name":"strip","expression":"@note[@effective_date].fee_strip_received","rules":[{"description":"Assign strip to the note","type":"accumulate","context":[{"name":"fee_type","expression":"@strip.type"},{"name":"fee_name","expression":"@strip.feename"}],"config":{"filter":"@df.Date == pd.Timestamp(@strip.dt)","columns":["fee_strip_received"],"expression":"@strip.val"}}]}},{"description":"Identify accrual end dates","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''initaccenddt'',''initmatdt'', ''leaddays'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["periodstart","periodend","pmtdt","term","indexrefdt"],"function":{"name":"get_accrual_dates","module":"dates","package":"m61_finance.cre","parameters":["@df.Date","@df.clsdt[0]","@df.initaccenddt[0]","pd.Timestamp(@period_end_date)","@df.initpmtdt[0]","[pd.Timestamp(dt) for dt in @calendar[''US'']]","@df.leaddays[0]","@df.perenddtbuslag[0]","@df.paydatebusiessdaylag[0]"]}}},{"description":"Identify io term end date","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''initpmtdt'',''ioterm'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["io_term_end_date"],"expression":"@df.initpmtdt[0] + pd.DateOffset(months=@df.ioterm[0] - 1)"}},{"description":"Read actuals - Payment date","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''actuals''])","config":{"foreach_variable_name":"actual","expression":"[x for x in @note[@effective_date].actuals if x.account in [''periodpikintpaid'', ''periodint'']]","rules":[{"description":"Assign actuals to df","type":"accumulate","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.term > 0) & (@df.pmtdt == pd.Timestamp(@actual.dt)) & (@df.Date == @df.periodend)","columns":"[''act_'' + @actual.account]","expression":"@actual.val"}}]}},{"description":"Read actuals - Transaction date","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''actuals''])","config":{"foreach_variable_name":"actual","expression":"[x for x in @note[@effective_date].actuals if x.account in [''pikprinpaid'']]","rules":[{"description":"Assign actuals to df","type":"accumulate","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.Date == pd.Timestamp(@actual.dt))","columns":"[''act_'' + @actual.account]","expression":"@actual.val"}}]}},{"description":"Calculate Schedule Principal - Debt Service Override","type":"assignment","condition":"@note[@effective_date].monamovrd > 0","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.term > 0) & (@df.Date == @df.periodend) & (@df.Date < @df.initmatdt)","columns":["schprin"],"expression":"@df.monamovrd"}},{"description":"Calculate Schedule Principal - Amort Schedule","type":"foreach","condition":"(@note[@effective_date].monamovrd == 0) & (@if_exists(@note, [@effective_date], [''amsch'']))","config":{"foreach_variable_name":"amort","expression":"@note[@effective_date].amsch","rules":[{"description":"Assign amort to df","type":"accumulate","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.term > 0) & (@df.pmtdt == pd.Timestamp(@amort.dt)) & (@df.Date == @df.periodend)","columns":["schprin"],"expression":"@amort.val"}}]}},{"description":"Set Discount/Premium - Initialize","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''discount'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["discount"],"value":0}},{"description":"Set Discount/Premium","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''discount'']))","config":{"filter":"(@df.Date == @df.clsdt)","columns":["discount"],"expression":"@note[@effective_date].discount * -1"}},{"description":"Set Capitalized Closing Costs - Initialize","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''capcosts'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["capcosts"],"value":0}},{"description":"Set Capitalized Closing Costs","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''capcosts'']))","config":{"filter":"(@df.Date == @df.clsdt)","columns":["capcosts"],"expression":"@note[@effective_date].capcosts"}},{"description":"Identify Index Rate","type":"assignment","condition":"@is_legal_note & @is_closed_note","config":{"columns":["indexrate"],"function":{"name":"get_index_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@index","@df.roundmethod[0]","@df.precision[0]","@df.clsdt[0]","@df.initresetdt[0]","@df[@df.term >= 1].periodstart.unique()","@df[@df.term >= 1].indexrefdt.unique()","@df.initindex[0]","@df.index_floor_val","@df.index_cap_val"]}}},{"description":"Identify All In Coupon Rate","type":"assignment","condition":"@is_legal_note & @is_closed_note","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["allincouponrate","allinadjfactor"],"function":{"name":"get_all_in_coupon_rate","module":"rates","package":"m61_finance.cre","parameters":["@df.coupon_floor_val","@df.spread_val","@df.spread_adj_factor","@df.rate_val","@df.rate_adj_factor","@df.indexrate",["allincouponrate","allinadjfactor"]]}}},{"description":"Calculate All In PIK Rate","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''pikrate'']))","context":[{"name":"is_floatingpik","expression":"@note[@effective_date][''pikrate''][0].rate == 0"}],"config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["allinpikrate"],"function":{"name":"get_allin_pikrate","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@df.pikrate_rate","@df.pikrate_spread","@df.indexrate","@df.pikrate_index_floor","@is_floatingpik"]}}},{"description":"Identify remaining term","type":"assignment","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (~@df.amterm.isna())","columns":["rem_term"],"expression":"@df.amterm - @df.term"}},{"description":"For each day, execute the following rules","type":"foreach","config":{"foreach_variable_name":"period","expression":"@df.Date[pd.Timestamp(@effective_date):].unique()","rules":[{"description":"Evaluate Period Filter","context":[{"name":"is_period","expression":"(@df.Date == @period) & (@df.clsdt.notna())"}]},{"description":"Calculate Scheduled Principal","type":"assignment","condition":"(@note[@effective_date].monamovrd == 0) & (not @if_exists(@note, [@effective_date], [''amsch'']))","config":{"filter":"@is_period & (@df.Date == @df.periodend) & (@df.Date > @df.io_term_end_date) & (@df.rem_term > 0) & (@df.amort_rate_val > 0)","columns":["schprin"],"function":{"name":"scheduled_principal","module":"balance","package":"m61_finance.cre","parameters":["@df.initbal","@df.amort_rate_val","@df.rem_term"]}}},{"description":"Calculate Daily PIK Interest","type":"assignment","config":{"filter":"@is_period","columns":["dailypikint"],"function":{"name":"daily_accrued_interest","module":"coupon","package":"m61_finance.cre","parameters":["@df.initbal","@df.allinpikrate","@df.pikrate_adj_factor"]}}},{"description":"Calculate PIK Interest Per Period","type":"assignment","context":[{"name":"cum_dailypikint","expression":"@df.loc[@df.term == @df.loc[@is_period, ''term''][0]].dailypikint.sum()"}],"config":{"filter":"@is_period & (@df.term > 0)","columns":["cum_dailypikint"],"expression":"@cum_dailypikint"}},{"description":"Calculate Accrual Period PIK Interest","type":"assignment","config":{"filter":"@is_period & (@df.term > 0) & (@df.Date == @df.periodend) & (@df.cum_dailypikint > @df.act_periodpikintpaid)","columns":["periodpikint"],"expression":"@df.cum_dailypikint - @df.act_periodpikintpaid"}},{"description":"Calculate Balloon Payment","type":"assignment","config":{"filter":"@is_period & (@df.Date == @df.initmatdt)","columns":["balloon"],"function":{"name":"balloon_payment","module":"balance","package":"m61_finance.cre","parameters":["@df.initbal","@df[@is_period].funding + @df[@is_period].paydown","@df.schprin"]}}},{"description":"Calculate ending balance","type":"assignment","context":[{"name":"ending_balance","function":{"name":"ending_balance","module":"balance","package":"m61_finance.cre","parameters":["@df[@is_period].initbal","@df[@is_period].funding + @df[@is_period].paydown","@df[@is_period].schprin","@df[@is_period].periodpikint","@df[@is_period].balloon"]}}],"config":{"filter":"@is_period","columns":["endbal"],"expression":"@ending_balance"}},{"description":"Calculate beginning balance","type":"assignment","config":{"filter":"(@df.Date == (pd.Timestamp(@period) + pd.DateOffset())) & (@df.clsdt.notna())","columns":["initbal"],"expression":"@ending_balance.to_numpy()"}}]}},{"description":"Calculate Daily Interest","type":"assignment","config":{"columns":["dailyint"],"function":{"name":"daily_accrued_interest","module":"coupon","package":"m61_finance.cre","parameters":["@df.initbal","@df.allincouponrate","@df.allinadjfactor"]}}},{"description":"Calculate Cumulative Interest - Convert to Float","type":"assignment","config":{"columns":["float_dailyint"],"expression":"@df.dailyint.astype(''float64'')"}},{"description":"Calculate Cumulative Interest","type":"assignment","config":{"columns":["cum_dailyint"],"expression":"@df.groupby([''Note'', ''term'']).float_dailyint.cumsum()"}},{"description":"Calculate Stub Interest","type":"assignment","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.term == 0) & (@df.Date == @df.periodend)","columns":["stubint"],"expression":"@df.stubintovrd if  @note[@effective_date].stubintovrd > 0 else @df.cum_dailyint"}},{"description":"Calculate Accrual Period Interest for periods without actuals","type":"assignment","context":[{"name":"last_period_with_actuals","expression":"max([pd.Timestamp(x.dt) for x in @note[@effective_date].get(''actuals'', [])], default=@df.Date[0] - pd.DateOffset())"}],"config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.term > 0) & (@df.Date == @df.periodend) & (@df.Date > @last_period_with_actuals)","columns":["periodint"],"expression":"@df.cum_dailyint"}},{"description":"For each fee, process below rules","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''fee''])","config":{"foreach_variable_name":"fee","expression":"@note[@effective_date].fee","rules":[{"description":"For each account, calculate fee","type":"foreach","config":{"foreach_variable_name":"account","expression":"@config.fee.config[@fee.type].accounts","rules":[{"description":"Calculate Fee","type":"accumulate","context":[{"name":"fee_type","expression":"@fee.type"},{"name":"fee_name","expression":"@fee.feename"},{"name":"fee_filter","expression":"((@df.Date == pd.Timestamp(@fee.startdt)) & (pd.Timestamp(@effective_date) <= pd.Timestamp(@fee.startdt))) if @config.fee.config[@fee.type].coverage == ''Date Specific'' else ((@df.Date >= pd.Timestamp(@fee.startdt)) & (@df.Date <= pd.Timestamp(@fee.enddt)) & (@df.Date >= pd.Timestamp(@effective_date)))"}],"config":{"filter":"(@fee_filter) & (@df[@account] != 0)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["@df[@account]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl"]}}}]}}]}},{"description":"Calculate Gross Deferred Fee for the Effective Date","type":"assignment","config":{"filter":"@df.Date >= pd.Timestamp(@effective_date)","columns":["gross_def_fees"],"expression":"@df.fee_incl_lv_yield.sum()"}},{"description":"Calculate Clean Cost","type":"assignment","config":{"filter":"@df.Date >= pd.Timestamp(@effective_date)","columns":["clean_cost"],"expression":"@df.endbal - @df.gross_def_fees + @df.discount  + @df.capcosts"}},{"description":"Calculate Clean Cost - Convert to Float","type":"assignment","config":{"columns":["float_clean_cost"],"expression":"@df.clean_cost.astype(''float64'')"}},{"description":"For each note, execute the basis rules","type":"foreach","condition":"@calc_basis","config":{"foreach_variable_name":"note","expression":"@notes.values()","rules":[{"description":"Calculate Level Yield - Deferred Fee Yield","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","context":[{"name":"prev_gaapbasis","expression":"-@df.at[(pd.Timestamp(@effective_date), @note.id), ''initbal''] if @is_closing_effective_date else -@df.at[(pd.Timestamp(@effective_date) - pd.DateOffset(), @note.id), ''gaapbasis'']"}],"config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["levyld"],"function":{"name":"calculate_level_yield","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal - @df.endbal + @df.fee_incl_lv_yield","pd.Timestamp(@effective_date) if @is_closing_effective_date else (pd.Timestamp(@effective_date) - pd.DateOffset())","@prev_gaapbasis"]}}},{"description":"Calculate Gaap Basis - Deferred Fee Basis","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["gaapbasis"],"function":{"name":"calculate_gaapbasis","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal-@df.endbal","@df.fee_incl_lv_yield","@df.levyld[0]"]}}},{"description":"Calculate Fee Amort","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["feeamort"],"function":{"name":"calculate_feeamort","module":"basis","package":"m61_finance.cre","parameters":["@df.initbal-@df.endbal","@df.fee_incl_lv_yield","@df.gaapbasis"]}}},{"description":"Calculate Cumulative Amort(Def Fee) - Convert to Float","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["float_am_fee"],"expression":"@df.feeamort.astype(''float64'')"}},{"description":"Calculate Cumulative Amort (Def Fee)","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["cum_am_fee"],"expression":"@df.float_am_fee.cumsum()"}},{"description":"Calculate Level Yield - Discount/Prmium Yield","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","context":[{"name":"prev_gaapbasis","expression":"-@df.at[(pd.Timestamp(@effective_date), @note.id), ''initbal''] if @is_closing_effective_date else -@df.at[(pd.Timestamp(@effective_date) - pd.DateOffset(), @note.id), ''bas_disc'']"}],"config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["yld_disc"],"function":{"name":"calculate_level_yield","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal-@df.endbal+@df.discount","pd.Timestamp(@effective_date) if @is_closing_effective_date else (pd.Timestamp(@effective_date) - pd.DateOffset())","@prev_gaapbasis"]}}},{"description":"Calculate Gaap Basis - Discout/Premium Basis","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["bas_disc"],"function":{"name":"calculate_gaapbasis","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal-@df.endbal","@df.discount","@df.yld_disc[0]"]}}},{"description":"Calculate Fee Amort","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["am_disc"],"function":{"name":"calculate_feeamort","module":"basis","package":"m61_finance.cre","parameters":["@df.initbal-@df.endbal","@df.discount","@df.bas_disc"]}}},{"description":"Calculate Cumulative Amort(Discount) - Convert to Float","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["float_am_disc"],"expression":"@df.am_disc.astype(''float64'')"}},{"description":"Calculate Cumulative Amort (Discout)","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["cum_am_disc"],"expression":"@df.float_am_disc.cumsum()"}},{"description":"Calculate Level Yield - Capitalized Costs","type":"assignment